// ROLLUP_NO_REPLACE 
 const _20260326Lareunionpourenparler = "{\"parsed\":{\"_path\":\"/fr/20260326-lareunionpourenparler\",\"_dir\":\"fr\",\"_draft\":false,\"_partial\":false,\"_locale\":\"\",\"title\":\"La réunion « pour en parler »\",\"description\":\"Une réflexion sur la fameuse réunion 'pour en parler' : pourquoi elle naît, comment l'éviter, et comment obtenir des décisions claires sans perdre de temps.\",\"image\":\"/images/articles/reunion.jpg\",\"createdAt\":\"2026-03-26\",\"keywords\":\"réunion, productivité, tech, marketing digital, réunion inutile, ego, développement\",\"body\":{\"type\":\"root\",\"children\":[{\"type\":\"element\",\"tag\":\"h1\",\"props\":{\"id\":\"la-réunion-pour-en-parler\"},\"children\":[{\"type\":\"text\",\"value\":\"La réunion « pour en parler »\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Dans mon domaine de travail, il existe un mal.\\nUne endémie.\\nNon, pas la « réunion de crise », ni le « kickoff ».\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Celle-là n'apparaît que lorsque les vagues de l'ego et du manque d'arguments — soigneusement cultivés par une système éducatif qui récompense la restitution — viennent se briser sur le mur de la réalité technique.\"}]},{\"type\":\"element\",\"tag\":\"h3\",\"props\":{\"id\":\"la-réunion-pour-en-parler-1\"},\"children\":[{\"type\":\"text\",\"value\":\"La réunion « pour en parler ».\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Ça commence toujours de la même façon. Une demande. Formulée avec la désinvolture de quelqu'un qui n'aura pas à la réaliser.\\nFormulée entre deux messages, comme si l’effort en temps et ressources qu’elle représente n’existait pas. Une demande dont la taille est inversement proportionnelle à l’aplomb avec laquelle elle est posée.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"En réponse, on envoie une analyse technique : options comparées, risques anticipés, recommandation d'outils qui font déjà le travail, plan de développement détaillé. En d'autres termes, on réfléchit à la place de celui qui n'a pas pris le temps de le faire.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Le retour est immédiat — et vague.\\n\"},{\"type\":\"element\",\"tag\":\"em\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"« Je ne vois pas trop. Je ne suis pas à l'aise avec ça. »\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Suivi par la proposition rituelle :\\n\"},{\"type\":\"element\",\"tag\":\"em\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"« Est-ce qu'on peut faire un call pour en parler ? »\"}]},{\"type\":\"text\",\"value\":\"\\nCe qui, traduit, donne :\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"em\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"« Je n'ai pas de contre-argument. Juste une conviction, nue, flottant dans au dessus de fil de discussion comme une déclaration souveraine. »\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Le vrai problème est plus profond que l'ego d'un collègue ou la culture d'une boîte.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Il est structurel.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Notre système éducatif — en Afrique francophone, en France ou ailleurs dans la sphère héritée du modèle francophone — ne forme pas, contrairement au monde anglo-saxon à la réflexion contradictoire et au pragmatisme.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Il forme à la restitution.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"On apprend à réciter, à valider, à cocher des cases. On récompense celui qui donne la bonne réponse, pas celui qui pose la meilleure question. Le débat n'est pas une compétence qu'on développe — c'est une menace qu'on apprend à esquiver.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"La réunion inutile est une conséquence de ce manque de formation.\"}]},{\"type\":\"element\",\"tag\":\"ul\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Personne n'a appris à formuler une objection rigoureuse face aux enseignants.\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Personne n'a appris à distinguer une intuition d'un argument.\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"On convoque donc une réunion — parce que la réunion, elle, donne l'illusion du sérieux .\"},{\"type\":\"element\",\"tag\":\"br\",\"props\":{},\"children\":[]},{\"type\":\"text\",\"value\":\"\\nSans en exiger la substance.\"}]},{\"type\":\"element\",\"tag\":\"h3\",\"props\":{\"id\":\"que-faut-il-faire\"},\"children\":[{\"type\":\"text\",\"value\":\"Que faut-il faire ?\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"À cet instant, il faut éviter de tomber dans le piège d’une énième réunion fantôme, car vous avez proposé une solution argumentée et documentée. Rien de productif ne sortira de cette réunion — je vous le garantis.\\nSoyez pragmatiques, et demandez à votre interlocuteur de formuler par écrit ses appréhensions. C’est une base saine pour continuer l'échange.\"}]},{\"type\":\"element\",\"tag\":\"h3\",\"props\":{\"id\":\"et-ça-a-marché-dans-ton-cas\"},\"children\":[{\"type\":\"text\",\"value\":\"Et ça a marché dans ton cas ?\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Oui, mais en insistant... dans beaucoup (trop) de cas, j’ai eu droit à l'une de ces réponses :\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"« On verra. »\\n« C'est pas si urgent que ça. »\\n« Je suis occupé pour l'instant. »\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Dans ces cas, insistez, pas pour humilier — mais pour aider la personne à formuler ce qui le gêne, et transformer les idées floues vraies objections. Et si, malgré vos efforts, la réponse écrite ne vient pas — ou est vide — pas de réunion, car une réunion utile commence par une phrase utile.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"PS : Si malgré tout vous décidez de tenir cette réunion, prévoyez un ordre du jour, un temps limité — 10 minutes max, sans retard toléré — et une question unique à trancher.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Avec des arguments.\"}]}],\"toc\":{\"title\":\"\",\"searchDepth\":2,\"depth\":2,\"links\":[{\"id\":\"la-réunion-pour-en-parler-1\",\"depth\":3,\"text\":\"La réunion « pour en parler ».\"},{\"id\":\"que-faut-il-faire\",\"depth\":3,\"text\":\"Que faut-il faire ?\"},{\"id\":\"et-ça-a-marché-dans-ton-cas\",\"depth\":3,\"text\":\"Et ça a marché dans ton cas ?\"}]}},\"_type\":\"markdown\",\"_id\":\"content:fr:20260326-lareunionpourenparler.md\",\"_source\":\"content\",\"_file\":\"fr/20260326-lareunionpourenparler.md\",\"_stem\":\"fr/20260326-lareunionpourenparler\",\"_extension\":\"md\",\"sitemap\":{\"loc\":\"/fr/20260326-lareunionpourenparler\"}},\"hash\":\"brqbMEMa16\"}";

export { _20260326Lareunionpourenparler as default };
